function dosSumas(nums, objetivo) {
  const mapa = {};
  for (let i = 0; i < nums.length; i++) {
    const complemento = objetivo - nums[i];
    if (complemento in mapa) return [mapa[complemento], i];
    mapa[nums[i]] = i;
  }
}

