function esValido(s) {
  const pila = [];
  const pares = { '(': ')', '[': ']', '{': '}' };
  for (let char of s) {
    if (pares[char]) pila.push(char);
    else if (pares[pila.pop()] !== char) return false;
  }
  return pila.length === 0;
}
